+/// Filter int32 with range (BETWEEN): returns indices where low <= val <= high
+export fn filterInt32Range(
+    data_ptr: [*]const i32,
+    len: usize,
+    low: i32,
+    high: i32,
+    out_indices: [*]u32,
+    max_indices: usize,
+) usize {
+    var out_count: usize = 0;
+    for (0..len) |i| {
+        if (out_count >= max_indices) break;
+        const v = data_ptr[i];
+        if (v >= low and v <= high) {
+            out_indices[out_count] = @intCast(i);
+            out_count += 1;
+        }
+    }
+    return out_count;
+}
